import { Field as FieldPrimitive, useField, useFieldContext } from '@ark-ui/react/field';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Field.module.css';

type FieldItemProps = ComponentProps<'div'> & ComponentProps<typeof FieldPrimitive.Item>;

const FieldRoot = forwardRef<
  ComponentRef<typeof FieldPrimitive.Root>,
  ComponentProps<typeof FieldPrimitive.Root>
>(function FieldRoot({ className, ...props }, ref) {
  return (
    <FieldPrimitive.Root
      ref={ref}
      data-slot="field-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const FieldRootProvider = forwardRef<
  ComponentRef<typeof FieldPrimitive.RootProvider>,
  ComponentProps<typeof FieldPrimitive.RootProvider>
>(function FieldRootProvider({ className, ...props }, ref) {
  return (
    <FieldPrimitive.RootProvider
      ref={ref}
      data-slot="field-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

function FieldItem({ className, children, value, ...props }: FieldItemProps) {
  return (
    <FieldPrimitive.Item value={value}>
      <div
        data-slot="field-item"
        className={clsx(styles.item, normalizeClassName(className))}
        {...props}
      >
        {children}
      </div>
    </FieldPrimitive.Item>
  );
}

const FieldLabel = forwardRef<
  ComponentRef<typeof FieldPrimitive.Label>,
  ComponentProps<typeof FieldPrimitive.Label>
>(function FieldLabel({ className, ...props }, ref) {
  return (
    <FieldPrimitive.Label
      ref={ref}
      data-slot="field-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const FieldInput = forwardRef<
  ComponentRef<typeof FieldPrimitive.Input>,
  ComponentProps<typeof FieldPrimitive.Input>
>(function FieldInput({ className, ...props }, ref) {
  return (
    <FieldPrimitive.Input
      ref={ref}
      data-slot="field-input"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const FieldTextarea = forwardRef<
  ComponentRef<typeof FieldPrimitive.Textarea>,
  ComponentProps<typeof FieldPrimitive.Textarea>
>(function FieldTextarea({ className, ...props }, ref) {
  return (
    <FieldPrimitive.Textarea
      ref={ref}
      data-slot="field-textarea"
      className={clsx(styles.control, styles.textarea, normalizeClassName(className))}
      {...props}
    />
  );
});

const FieldSelect = forwardRef<
  ComponentRef<typeof FieldPrimitive.Select>,
  ComponentProps<typeof FieldPrimitive.Select>
>(function FieldSelect({ className, ...props }, ref) {
  return (
    <FieldPrimitive.Select
      ref={ref}
      data-slot="field-select"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const FieldHelperText = forwardRef<
  ComponentRef<typeof FieldPrimitive.HelperText>,
  ComponentProps<typeof FieldPrimitive.HelperText>
>(function FieldHelperText({ className, ...props }, ref) {
  return (
    <FieldPrimitive.HelperText
      ref={ref}
      data-slot="field-helper-text"
      className={clsx(styles.helperText, normalizeClassName(className))}
      {...props}
    />
  );
});

const FieldErrorText = forwardRef<
  ComponentRef<typeof FieldPrimitive.ErrorText>,
  ComponentProps<typeof FieldPrimitive.ErrorText>
>(function FieldErrorText({ className, ...props }, ref) {
  return (
    <FieldPrimitive.ErrorText
      ref={ref}
      data-slot="field-error-text"
      className={clsx(styles.errorText, normalizeClassName(className))}
      {...props}
    />
  );
});

const FieldRequiredIndicator = forwardRef<
  ComponentRef<typeof FieldPrimitive.RequiredIndicator>,
  ComponentProps<typeof FieldPrimitive.RequiredIndicator>
>(function FieldRequiredIndicator({ className, ...props }, ref) {
  return (
    <FieldPrimitive.RequiredIndicator
      ref={ref}
      data-slot="field-required-indicator"
      className={clsx(styles.requiredIndicator, normalizeClassName(className))}
      {...props}
    />
  );
});

const Field = Object.assign(FieldRoot, {
  Root: FieldRoot,
  RootProvider: FieldRootProvider,
  Item: FieldItem,
  Label: FieldLabel,
  Input: FieldInput,
  Textarea: FieldTextarea,
  Select: FieldSelect,
  HelperText: FieldHelperText,
  ErrorText: FieldErrorText,
  RequiredIndicator: FieldRequiredIndicator,
  Context: FieldPrimitive.Context,
});

export { Field, useField, useFieldContext };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    gap: var(--moduix-field-gap, var(--moduix-spacing-1));
    width: var(--moduix-field-width, 100%);
    max-width: var(--moduix-field-max-width, none);
    color: var(--moduix-field-color, var(--moduix-color-foreground));

    &[data-disabled] {
      opacity: var(--moduix-field-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .item {
    display: grid;
    gap: var(--moduix-field-item-gap, var(--moduix-spacing-1));
  }

  .label {
    display: inline-flex;
    align-items: center;
    gap: var(--moduix-field-label-gap, var(--moduix-spacing-2));
    color: var(--moduix-field-label-color, var(--moduix-color-foreground));
    font-size: var(--moduix-field-label-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-field-label-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-field-label-line-height, var(--moduix-line-height-text-sm));

    &[data-disabled] {
      opacity: var(--moduix-field-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .helperText {
    margin: 0;
    color: var(--moduix-field-description-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-field-description-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-field-description-line-height, var(--moduix-line-height-text-sm));

    &[data-disabled] {
      opacity: var(--moduix-field-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .control {
    box-sizing: border-box;
    width: var(--moduix-field-control-width, 100%);
    min-height: var(--moduix-field-control-height, var(--moduix-size-md));
    margin: 0;
    border: var(--moduix-field-control-border-width, var(--moduix-border-width-sm))
      var(--moduix-field-control-border-style, solid)
      var(--moduix-field-control-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-field-control-radius, var(--moduix-radius-md));
    padding: var(--moduix-field-control-padding-y, var(--moduix-spacing-1))
      var(--moduix-field-control-padding-x, var(--moduix-spacing-3-5));
    background-color: var(--moduix-field-control-bg, var(--moduix-color-background));
    color: var(--moduix-field-control-color, var(--moduix-color-foreground));
    font: inherit;
    font-size: var(--moduix-field-control-font-size, var(--moduix-text-md));
    line-height: var(--moduix-field-control-line-height, var(--moduix-line-height-text-md));
    outline: var(
        --moduix-field-focus-ring-width,
        var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
      )
      solid transparent;
    outline-offset: var(--moduix-field-focus-ring-offset, var(--moduix-focus-ring-inset-offset));
    transition:
      border-color var(--moduix-field-control-transition, var(--moduix-transition-default)),
      outline-color var(--moduix-field-control-transition, var(--moduix-transition-default)),
      opacity var(--moduix-field-control-transition, var(--moduix-transition-default));

    &::placeholder {
      color: var(--moduix-field-control-placeholder-color, var(--moduix-color-muted-foreground));
    }

    &:focus-visible {
      outline-color: var(--moduix-field-focus-ring-color, var(--moduix-color-ring));
    }

    &[data-invalid] {
      border-color: var(
        --moduix-field-control-border-color-invalid,
        var(--moduix-color-destructive)
      );

      &:focus-visible {
        outline-color: var(
          --moduix-field-control-border-color-invalid,
          var(--moduix-color-destructive)
        );
      }
    }

    &[data-disabled],
    &:disabled {
      pointer-events: none;
      opacity: var(--moduix-field-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .textarea {
    min-height: var(--moduix-field-textarea-min-height, 5rem);
    resize: vertical;
  }

  .errorText {
    margin: 0;
    color: var(--moduix-field-error-color, var(--moduix-color-destructive));
    font-size: var(--moduix-field-error-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-field-error-line-height, var(--moduix-line-height-text-sm));

    &[data-disabled] {
      opacity: var(--moduix-field-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .requiredIndicator {
    color: var(--moduix-field-required-indicator-color, var(--moduix-color-destructive));
  }
}
